/* ---------------------------------------------------------------------
   Reveal-on-scroll primitive
--------------------------------------------------------------------- */
function Reveal({ as: Tag = "div", className = "", delay = 0, children, ...rest }) {
  const ref = useRef(null);
  const [seen, setSeen] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((e) => {
          if (e.isIntersecting) {
            setSeen(true);
            io.unobserve(el);
          }
        });
      },
      { threshold: 0.16, rootMargin: "0px 0px -8% 0px" }
    );
    io.observe(el);
    return () => io.disconnect();
  }, []);
  return (
    <Tag
      ref={ref}
      className={`reveal ${seen ? "reveal--in" : ""} ${className}`}
      style={{ transitionDelay: `${delay}ms` }}
      {...rest}
    >
      {children}
    </Tag>
  );
}

function Img({ src, alt, fallbackA, fallbackB, className }) {
  const [err, setErr] = useState(false);
  return (
    <img
      className={className}
      src={err ? FALLBACK(fallbackA, fallbackB) : src}
      alt={alt}
      loading="lazy"
      onError={() => setErr(true)}
    />
  );
}

/* ---------------------------------------------------------------------
   Loader — the sun-mark assembling, then the arrow "ships out"
--------------------------------------------------------------------- */
const LOADER_CAPTIONS = [
  "Preparing the manifest…",
  "Packing the cargo…",
  "Charting the route…",
  "Clearing customs…",
];

function Loader({ done }) {
  const [pct, setPct] = useState(0);

  useEffect(() => {
    const start = Date.now();
    const DURATION = 1300;
    let raf;
    const tick = () => {
      const t = Math.min(1, (Date.now() - start) / DURATION);
      const eased = 1 - Math.pow(1 - t, 3);
      setPct(Math.round(eased * 100));
      if (t < 1) raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, []);

  return (
    <div className={`loader ${done ? "loader--out" : ""}`} aria-hidden={done}>
      <div className="loader__mark">
        <img src={LOGO_SRC} alt="" />
      </div>
      <div className="loader__word">SPD&nbsp;EXPORTS</div>
      <div className="loader__bar"><span style={{ width: `${pct}%` }} /></div>
    </div>
  );
}

/* ---------------------------------------------------------------------
   Trade-route hero graphic — Madurai to the world, line draws in
--------------------------------------------------------------------- */
function RouteMap() {
  const dots = [
    { x: 150, y: 210, label: "MADURAI · ORIGIN", origin: true },
    { x: 430, y: 90 },
    { x: 610, y: 150 },
    { x: 560, y: 250 },
    { x: 340, y: 60 },
  ];
  return (
    <svg className="route" viewBox="0 0 700 300" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
      {dots.slice(1).map((d, i) => (
        <path
          key={i}
          className="route__line"
          d={`M150,210 Q ${(150 + d.x) / 2},${Math.min(210, d.y) - 40} ${d.x},${d.y}`}
          style={{ animationDelay: `${700 + i * 260}ms` }}
        />
      ))}
      {dots.map((d, i) => (
        <g key={i} className="route__dot" style={{ animationDelay: `${1400 + i * 140}ms` }}>
          <circle cx={d.x} cy={d.y} r={d.origin ? 7 : 4.5} />
          {d.origin && <circle cx={d.x} cy={d.y} r={13} className="route__pulse" />}
        </g>
      ))}
    </svg>
  );
}

